import{p as l,v as c,c as i,o as t,ag as g,j as n,ah as m,e as b,ai as f,Z as p,t as k,a as w}from"./chunks/framework.091VdYs-.js";const v={key:0,class:"cv-gate"},S={key:0,class:"error-msg"},A={key:1,class:"cv-download-area"},z=JSON.parse('{"title":"Lebenslauf","description":"","frontmatter":{"sidebar":false,"aside":false},"headers":[],"relativePath":"lebenslauf.md","filePath":"lebenslauf.md"}'),P={name:"lebenslauf.md"},T=Object.assign(P,{setup(D){const r=l(""),s=l(!1),a=l(""),h=u=>/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(u),o=()=>{if(a.value="",!r.value.trim()){a.value="Bitte eine E-Mail-Adresse eingeben.";return}if(!h(r.value.trim())){a.value="Bitte eine gültige E-Mail-Adresse eingeben.";return}localStorage.setItem("cv_access_email",r.value.trim()),s.value=!0};return c(()=>{localStorage.getItem("cv_access_email")&&(s.value=!0)}),(u,e)=>(t(),i("div",null,[e[4]||(e[4]=g('<h1 id="lebenslauf" tabindex="-1">Lebenslauf <a class="header-anchor" href="#lebenslauf" aria-label="Permalink to &quot;Lebenslauf&quot;">​</a></h1><hr><h2 id="arthur-schimpf" tabindex="-1">Arthur Schimpf <a class="header-anchor" href="#arthur-schimpf" aria-label="Permalink to &quot;Arthur Schimpf&quot;">​</a></h2><p>Softwareentwickler · Karlsruhe · <a href="mailto:Arthur.Schimpf@gmx.de" target="_blank" rel="noreferrer">Arthur.Schimpf@gmx.de</a></p><hr><h2 id="berufliche-stationen" tabindex="-1">Berufliche Stationen <a class="header-anchor" href="#berufliche-stationen" aria-label="Permalink to &quot;Berufliche Stationen&quot;">​</a></h2><h3 id="digital-transformation-projects-programmer" tabindex="-1">Digital Transformation Projects Programmer <a class="header-anchor" href="#digital-transformation-projects-programmer" aria-label="Permalink to &quot;Digital Transformation Projects Programmer&quot;">​</a></h3><p><strong>Hellmann Worldwide Logistics SE</strong> · Osnabrück (remote) · 2025 – heute</p><p>Arbeit in einem kleinen, spezialisierten Team an der Migration eines AS400-Systems in eine moderne Microservice-Architektur. Der technische Kern war die Entwicklung einer vollständigen ETL-Pipeline: Extraktion der Daten aus dem Altsystem, Transformation und Validierung über einen eigenen Service, Einspeisung in das neue Domänenmodell und Persistierung in einer relationalen Datenbank. Darüber hinaus wurde ein Angular-Frontend für die operativen Nutzer entwickelt, das die Bedienung der neuen Systeme ablöst.</p><p>Die Zusammenarbeit erfolgte eng mit Fachbereichs-Experten, die die fachlichen Anforderungen an das Offerten- und Kalkulationssystem eingebracht haben. Technisch: Java, Spring Boot, REST, Angular, PostgreSQL. Das Team bestand aus einem Senior-Entwickler, einem Product Owner und zwei Fachlichen.</p><p>Die Stelle entfiel im Rahmen einer unternehmensweiten Restrukturierung – Hellmann hat konzernweit einen erheblichen Teil der Belegschaft abgebaut. Der Abgang war wirtschaftlich bedingt, nicht leistungsbedingt.</p><hr><h3 id="softwareentwickler" tabindex="-1">Softwareentwickler <a class="header-anchor" href="#softwareentwickler" aria-label="Permalink to &quot;Softwareentwickler&quot;">​</a></h3><p><strong>Infokom GmbH</strong> (Tochtergesellschaft der EurobaustoffHandels-AG) · Karlsruhe · 2023 – 2025</p><p>Die Infokom verantwortet die IT-Entwicklung innerhalb der Eurobaustoff-Gruppe. Ich war Teil eines kleinen Entwicklungsteams, das an drei wesentlichen Projekten gearbeitet hat:</p><p><strong>ZFWEB – ZentralFaktur Web.</strong> Eine vollständige Web-Anwendung zur Verwaltung und Verarbeitung von Rechnungsdaten. Ich habe dieses Projekt von Beginn an verantwortet: Konzeption der Architektur, Aufbau der ersten Versionen, Implementierung der zentralen Funktionen, Einrichtung der CI/CD-Pipeline und Etablierung eines Scrum-Prozesses inklusive Board und Sprint-Struktur. In den ersten eineinhalb Jahren war ich der primäre Entwickler dieser Anwendung, bevor weitere Kollegen eingestiegen sind. Thematisch: Rechnungserfassung, Versand von E-Rechnungen nach den aktuellen Standards (ZUGFeRD, XRechnung), Archivierung. Technisch: Vaadin, Spring Boot, PostgreSQL, Hibernate, GitLab CI.</p><p><strong>AS400-Migration.</strong> Parallele Mitarbeit an der Konzeption und Vorbereitung einer langfristigen Systemablösung. Ziel war die Migration von Millionen von Datensätzen aus einem AS400-System in eine moderne Umgebung auf Basis von CockroachDB. Das Projekt war auf mehrere Jahre angelegt und erforderte enge Abstimmung mit Fachbereichen sowie Zusammenarbeit mit einem externen Datenbankspezialisten-Team von CockroachDB selbst. Diese Erfahrung – Analyse eines komplexen Altsystems, Anforderungserhebung mit Fachabteilungen, Datenbankdesign für Migrationsprojekte – hat sich direkt in meiner Arbeit bei Hellmann als wertvoll erwiesen.</p><p><strong>InfoGPT.</strong> Eine interne Chat-Anwendung, vergleichbar mit ChatGPT, für den Einsatz innerhalb der Unternehmensgruppe. Ich war als zweiter Entwickler an diesem Projekt beteiligt, gemeinsam mit einem englischsprachigen Kollegen. Technisch ebenfalls auf Vaadin-Basis.</p><p>Gegen Ende der Tätigkeit übernahm ich zusätzlich die Begleitung von Auszubildenden und dualen Studenten in technischen Themen. Ich entschied mich zum Wechsel, weil ich meinen Fokus konsequent auf Backend-Entwicklung und Architektur legen wollte.</p><hr><h3 id="webentwickler" tabindex="-1">Webentwickler <a class="header-anchor" href="#webentwickler" aria-label="Permalink to &quot;Webentwickler&quot;">​</a></h3><p><strong>abas Software GmbH</strong> (heute: Forterro) · Karlsruhe · 2022 – 2023</p><p>Nach Abschluss der Ausbildung war ich ein halbes Jahr als Webentwickler im Professional Services tätig. Das Kernprodukt der Abteilung: Shop-Plugins, die das hausinterne abas ERP-System mit externen E-Commerce-Shops verbinden. Aufgabe war die technische Integration dieser Systeme sowie die Implementierung kundenspezifischer Themes und Funktionserweiterungen nach Kundenvorgaben.</p><p>Dabei arbeitete ich mit einem hausinternen Framework auf Basis von Spring Boot im Backend und Vue.js im Frontend – dem gleichen Stack, der mich auch in späteren Stationen begleitet hat. Die Arbeit war kundenprojektgetrieben mit klaren Zeit- und Kostenrahmen, was frühzeitig ein Verständnis für kommerzielle Softwarelieferung und das Arbeiten unter definierten Budgets vermittelt hat.</p><hr><h3 id="auszubildender-fachinformatiker-anwendungsentwicklung" tabindex="-1">Auszubildender Fachinformatiker Anwendungsentwicklung <a class="header-anchor" href="#auszubildender-fachinformatiker-anwendungsentwicklung" aria-label="Permalink to &quot;Auszubildender Fachinformatiker Anwendungsentwicklung&quot;">​</a></h3><p><strong>abas Software GmbH</strong> · Karlsruhe · 2019 – 2022</p><p>Duale Ausbildung an der Heinrich-Hertz-Schule Karlsruhe, abgeschlossen 2022. Parallel zur schulischen Ausbildung praktische Mitarbeit an Webanwendungen und Integrationsprojekten. Grundlegende Kenntnisse in Java, Spring Boot, Web-Technologien und professionellen Entwicklungsprozessen.</p><hr><h2 id="ausbildung" tabindex="-1">Ausbildung <a class="header-anchor" href="#ausbildung" aria-label="Permalink to &quot;Ausbildung&quot;">​</a></h2><p><strong>Fachinformatiker Anwendungsentwicklung</strong> Heinrich-Hertz-Schule Karlsruhe · Abschluss 2022</p><p><strong>Fach-Abitur Wirtschaft (BWL / VWL)</strong> Ludwig-Erhard Gymnasium Karlsruhe · 2019</p><hr><h2 id="technische-kenntnisse" tabindex="-1">Technische Kenntnisse <a class="header-anchor" href="#technische-kenntnisse" aria-label="Permalink to &quot;Technische Kenntnisse&quot;">​</a></h2><p>Java (LTS bis 21), Spring Boot 3, Spring MVC / Data JPA / Security / AI, PostgreSQL, MySQL, Flyway, Hibernate/JPA, Kafka, Vue.js 3, React / Next.js, Angular, Vaadin (21–25), TypeScript, Docker, GitLab CI, Kubernetes, Testcontainers, JUnit 4/5, OpenAPI.</p><p>Eine ausführliche Beschreibung mit konkreten Projektreferenzen und ehrlicher Einschätzung des jeweiligen Kenntnisstands findet sich unter <a href="/kenntnisse.html">Technische Kenntnisse</a>.</p><hr><h2 id="weitere-informationen" tabindex="-1">Weitere Informationen <a class="header-anchor" href="#weitere-informationen" aria-label="Permalink to &quot;Weitere Informationen&quot;">​</a></h2><p>Eigene Softwareprojekte (TinyBill, Bewerber-Schmiede, DailyDev) unter <a href="/projekte/">dev-arts.de/projekte</a>.</p><hr><h2 id="lebenslauf-als-pdf" tabindex="-1">Lebenslauf als PDF <a class="header-anchor" href="#lebenslauf-als-pdf" aria-label="Permalink to &quot;Lebenslauf als PDF&quot;">​</a></h2>',41)),s.value?(t(),i("div",A,[...e[3]||(e[3]=[n("p",{style:{margin:"0 0 0.75rem 0","font-size":"0.95rem",color:"var(--vp-c-text-2)"}}," Danke. Der Lebenslauf steht zum Download bereit. ",-1),n("a",{href:"/downloads/cv-arthur-schimpf.pdf",download:"",class:"cv-download-link"}," Lebenslauf herunterladen (PDF) ",-1),n("p",{style:{margin:"0.75rem 0 0 0","font-size":"0.85rem",color:"var(--vp-c-text-3)"}},[w(" Bei Fragen stehe ich jederzeit per E-Mail zur Verfügung: "),n("a",{href:"mailto:Arthur.Schimpf@gmx.de"},"Arthur.Schimpf@gmx.de")],-1)])])):(t(),i("div",v,[e[1]||(e[1]=n("p",{style:{margin:"0 0 1.25rem 0","font-size":"0.95rem","line-height":"1.7",color:"var(--vp-c-text-2)"}}," Bitte hinterlassen Sie Ihre E-Mail-Adresse, um den Lebenslauf als PDF herunterzuladen. Ich melde mich bei Interesse gerne zurück. ",-1)),e[2]||(e[2]=n("label",{for:"cv-email"},"E-Mail-Adresse",-1)),m(n("input",{id:"cv-email","onUpdate:modelValue":e[0]||(e[0]=d=>r.value=d),type:"email",placeholder:"vorname.nachname@unternehmen.de",onKeyup:p(o,["enter"])},null,544),[[f,r.value]]),a.value?(t(),i("div",S,k(a.value),1)):b("",!0),n("button",{onClick:o},"Lebenslauf herunterladen")]))]))}});export{z as __pageData,T as default};
